#include <stdio.h>
int maxArea(int* height, int heightSize) {
    int max = 0;
    int left = 0;
    int right = heightSize - 1;
    while (left < right) {
        int area = (right - left) * (height[left] < height[right] ? height[left] : height[right]);
        max = max > area ? max : area;
        if (height[left] < height[right]) {
            left++;
        } else {
            right--;
        }
    }
    return max;
}

